(309, NULL, NULL, 'MG-R-20260227-31570', 'Goodwill elactric world', '9961898888', 'yahiyapeersha@gmail.com', 'Muscle grid solar star 6.2kw hybrid inverter 48v dc', 'Mg26001071', 'IN-150', NULL, '2026-02-24', 'uploads/invoices/309/invoice.jpg', NULL, 'hardware', 2, '2026-03-10 08:57:14', 2, 'Not working', NULL, 'Goodwill elactric world', 'Kulappully', '679122', '2026-02-27', 'Hardware Service – Awaiting Label', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 07:12:52', '2026-03-09 08:57:14', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(310, NULL, NULL, 'MG-R-20260227-88552', 'Good will elactric world', '9961898888', 'yahiyapeersha@gmal.com', 'Mucle grid solar star 6.2kw hybrid solar inverter 48v', 'Mg26001071', 'In 150', NULL, '2026-01-24', 'uploads/invoices/310/invoice.jpg', NULL, 'phone', NULL, NULL, NULL, 'Note working', NULL, 'Good will elactric world Kulappully palakkadu kerala', 'Kulappully', '679122', '2026-02-27', 'Resolved on Call', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 09:56:31', '2026-02-27 07:44:00', '2026-02-27 09:56:31', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(311, NULL, NULL, 'MG-R-20260228-12674', 'dev sharma', '7507898160', 'lovetemplegoa@gamil.com', 'MG-H48102E160D', '320122404090081', 'Order no #1025', NULL, '2024-02-02', 'uploads/invoices/311/invoice.jpg', NULL, 'phone', 3, '2026-03-13 15:06:03', 3, 'Dear MuscleGrid Service Centre Team,\r\n\r\nI am writing to request technical assistance for my MuscleGrid Hybrid 10kW inverter, which is currently not functioning. The unit is completely unresponsive, and even the display panel does not light up when I attempt to power it on.\r\n\r\nThe inverter was previously operating normally without any issues. However, it has now stopped working entirely. There are no indicator lights, no display activity, and no sound from the internal components such as fans or relays. I have checked the main AC input supply, battery connections, and solar PV input connections to ensure everything is properly connected. I also verified that the external breakers and isolators are in the ON position. Despite these checks, the inverter remains completely dead.\r\n\r\nThere was no unusual smell, smoke, or visible damage prior to the failure. The unit has been installed in a proper indoor location with adequate ventilation and within recommended operating temperature conditions.\r\n\r\nKindly advise on the possible cause of this issue and the next steps for troubleshooting. Please let me know if there are any reset procedures I can attempt safely. If the unit requires inspection or repair, I would appreciate guidance on how to proceed with warranty service or arranging a technician visit.\r\n\r\nI look forward to your prompt support in resolving this matter.\r\n\r\nSincerely', NULL, 'Love temple guesthouse, arambol, pernim,goa,403524', 'arambol, pernim', '403524', '2024-02-02', 'Call Support – Followup', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-28 10:00:05', '2026-03-12 15:06:03', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
